const fs = require('fs');
const html = fs.readFileSync('/home/openclaw/pangkas/index.html','utf8');
// Extract JS from script tag
const match = html.match(/<script>([\s\S]*)<\/script>/);
if (!match) { console.log('No script found!'); process.exit(1); }
const js = match[1];
try {
  new Function(js);
  console.log('✅ JavaScript syntax OK');
} catch(e) {
  console.log('❌ JS syntax error:', e.message);
}
// Check for essential functions
const needed = ['rp','waLink','uid','today','toast','openModal','closeModal','nav','subPage','goBack','renderPage',
  'obNext','obFinish','pinInput','checkPin','cartAdd','cartRemove','showPayment','processPayment',
  'showAddQueue','addQueue','qAction','showAddMember','addMember','deleteMember',
  'showAddAppt','addAppt','deleteAppt','exportCSV','exportJSON','importJSON',
  'payDebt','showAddExpense','addExpense','deleteExpense',
  'settShop','settStaff','settServices','settAddons','settGeneral','settBackup','settAbout',
  'showAddService','addService','editService','saveService','deleteService',
  'showAddAddon','addAddon','editAddon','saveAddon','deleteAddon',
  'addStaff','editStaffPin','saveStaffPin','deleteStaff','logout'];
const missing = needed.filter(fn => !js.includes('function ' + fn));
if (missing.length) console.log('❌ Missing functions:', missing.join(', '));
else console.log('✅ All', needed.length, 'required functions present');
"
